sql:
SELECT underwriter_id, COUNT(loan_id) AS total_loans_processed
FROM loan_origination
GROUP BY underwriter_id;

SELECT status_name
FROM loan_status
ORDER BY status_name;

external_knowledge:
- 'Top 5 borrowers' refers to the borrowers with the highest credit scores; 
- 'Latest loan status' implies the most recent status update for each loan; 
- 'Origination fees' are the fees associated with the initial setup of the loans.
